import{_ as o}from"./plugin-vue_export-helper-c27b6911.js";import{r as i,o as l,c as p,b as r,a as e,e as a,w as n,d as h}from"./app-75fed8c6.js";const s={},c=e("h2",{id:"meshlambertmaterial",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#meshlambertmaterial","aria-hidden":"true"},"#"),a(" MeshLambertMaterial")],-1),m=e("p",null,"一种非光泽表面的材质，没有镜面高光。",-1),f=e("p",null,"该材质使用基于非物理的Lambertian模型来计算反射率。 这可以很好地模拟一些表面（例如未经处理的木材或石材），但不能模拟具有镜面高光的光泽表面（例如涂漆木材）。",-1),u=e("p",null,"由于反射率和光照模型的简单性，MeshPhongMaterial，MeshStandardMaterial或者MeshPhysicalMaterial 上使用这种材质时会以一些图形精度为代价，得到更高的性能。",-1),x=h('<h2 id="构造器" tabindex="-1"><a class="header-anchor" href="#构造器" aria-hidden="true">#</a> 构造器</h2><h3 id="parameters-object" tabindex="-1"><a class="header-anchor" href="#parameters-object" aria-hidden="true">#</a> parameters : Object</h3><p>parameters - (可选)用于定义材质外观的对象，具有一个或多个属性。材质的任何属性都可以从此处传入(包括从Material继承的任何属性)</p><p>属性color例外，其可以作为十六进制字符串传递，默认情况下为 0xffffff（白色），内部调用Color.set(color)。</p><h2 id="属性" tabindex="-1"><a class="header-anchor" href="#属性" aria-hidden="true">#</a> 属性</h2>',5),b=h('<h3 id="alphamap-texture" tabindex="-1"><a class="header-anchor" href="#alphamap-texture" aria-hidden="true">#</a> .alphaMap : Texture</h3><p>alpha贴图是一张灰度纹理，用于控制整个表面的不透明度。（黑色：完全透明；白色：完全不透明）。 默认值为null。</p><p>仅使用纹理的颜色，忽略alpha通道（如果存在）。 对于RGB和RGBA纹理，WebGL渲染器在采样此纹理时将使用绿色通道， 因为在DXT压缩和未压缩RGB 565格式中为绿色提供了额外的精度。 Luminance-only以及luminance/alpha纹理也仍然有效。</p><h3 id="aomap-texture" tabindex="-1"><a class="header-anchor" href="#aomap-texture" aria-hidden="true">#</a> .aoMap : Texture</h3><p>该纹理的红色通道用作环境遮挡贴图。默认值为null。aoMap需要第二组UV。</p><h3 id="aomapintensity-float" tabindex="-1"><a class="header-anchor" href="#aomapintensity-float" aria-hidden="true">#</a> .aoMapIntensity : Float</h3><p>环境遮挡效果的强度。默认值为1。零是不遮挡效果。</p><h3 id="bumpmap-texture" tabindex="-1"><a class="header-anchor" href="#bumpmap-texture" aria-hidden="true">#</a> .bumpMap : Texture</h3><p>用于创建凹凸贴图的纹理。黑色和白色值映射到与光照相关的感知深度。凹凸实际上不会影响对象的几何形状，只影响光照。如果定义了法线贴图，则将忽略该贴图。</p><h3 id="bumpscale-float" tabindex="-1"><a class="header-anchor" href="#bumpscale-float" aria-hidden="true">#</a> .bumpScale : Float</h3><p>凹凸贴图会对材质产生多大影响。典型范围是0-1。默认值为1。</p><h3 id="color-color" tabindex="-1"><a class="header-anchor" href="#color-color" aria-hidden="true">#</a> .color : Color</h3><p>材质的颜色(Color)，默认值为白色 (0xffffff)。</p><h3 id="combine-integer" tabindex="-1"><a class="header-anchor" href="#combine-integer" aria-hidden="true">#</a> .combine : Integer</h3><p>如何将表面颜色的结果与环境贴图（如果有）结合起来。</p><p>选项为THREE.MultiplyOperation（默认值），THREE.MixOperation， THREE.AddOperation。如果选择多个，则使用.reflectivity在两种颜色之间进行混合。</p><h3 id="displacementmap-texture" tabindex="-1"><a class="header-anchor" href="#displacementmap-texture" aria-hidden="true">#</a> .displacementMap : Texture</h3><p>位移贴图会影响网格顶点的位置，与仅影响材质的光照和阴影的其他贴图不同，移位的顶点可以投射阴影，阻挡其他对象， 以及充当真实的几何体。位移纹理是指：网格的所有顶点被映射为图像中每个像素的值（白色是最高的），并且被重定位。</p><h3 id="displacementscale-float" tabindex="-1"><a class="header-anchor" href="#displacementscale-float" aria-hidden="true">#</a> .displacementScale : Float</h3><p>位移贴图对网格的影响程度（黑色是无位移，白色是最大位移）。如果没有设置位移贴图，则不会应用此值。默认值为1。</p><h3 id="displacementbias-float" tabindex="-1"><a class="header-anchor" href="#displacementbias-float" aria-hidden="true">#</a> .displacementBias : Float</h3><p>位移贴图在网格顶点上的偏移量。如果没有设置位移贴图，则不会应用此值。默认值为0。</p><h3 id="emissive-color" tabindex="-1"><a class="header-anchor" href="#emissive-color" aria-hidden="true">#</a> .emissive : Color</h3><p>材质的放射（光）颜色，基本上是不受其他光照影响的固有颜色。默认为黑色。</p><h3 id="emissivemap-texture" tabindex="-1"><a class="header-anchor" href="#emissivemap-texture" aria-hidden="true">#</a> .emissiveMap : Texture</h3><p>设置放射（发光）贴图。默认值为null。放射贴图颜色由放射颜色和强度所调节。 如果你有一个放射贴图，请务必将放射颜色设置为黑色以外的其他颜色。</p><h3 id="emissiveintensity-float" tabindex="-1"><a class="header-anchor" href="#emissiveintensity-float" aria-hidden="true">#</a> .emissiveIntensity : Float</h3><p>放射光强度。调节发光颜色。默认为1。</p><h3 id="envmap-texture" tabindex="-1"><a class="header-anchor" href="#envmap-texture" aria-hidden="true">#</a> .envMap : Texture</h3><p>环境贴图。默认值为null。</p><h3 id="flatshading-boolean" tabindex="-1"><a class="header-anchor" href="#flatshading-boolean" aria-hidden="true">#</a> .flatShading : Boolean</h3><p>定义材质是否使用平面着色进行渲染。默认值为false。</p><h3 id="fog-boolean" tabindex="-1"><a class="header-anchor" href="#fog-boolean" aria-hidden="true">#</a> .fog : Boolean</h3><p>材质是否受雾影响。默认为true。</p><h3 id="lightmap-texture" tabindex="-1"><a class="header-anchor" href="#lightmap-texture" aria-hidden="true">#</a> .lightMap : Texture</h3><p>光照贴图。默认值为null。lightMap需要第二组UV。</p><h3 id="lightmapintensity-float" tabindex="-1"><a class="header-anchor" href="#lightmapintensity-float" aria-hidden="true">#</a> .lightMapIntensity : Float</h3><p>烘焙光的强度。默认值为1。</p><h3 id="map-texture" tabindex="-1"><a class="header-anchor" href="#map-texture" aria-hidden="true">#</a> .map : Texture</h3><p>颜色贴图。可以选择包括一个alpha通道，通常与.transparent 或.alphaTest。默认为null。</p><h3 id="normalmap-texture" tabindex="-1"><a class="header-anchor" href="#normalmap-texture" aria-hidden="true">#</a> .normalMap : Texture</h3><p>用于创建法线贴图的纹理。RGB值会影响每个像素片段的曲面法线，并更改颜色照亮的方式。法线贴图不会改变曲面的实际形状，只会改变光照。 In case the material has a normal map authored using the left handed convention, the y component of normalScale should be negated to compensate for the different handedness.</p><h3 id="normalmaptype-integer" tabindex="-1"><a class="header-anchor" href="#normalmaptype-integer" aria-hidden="true">#</a> .normalMapType : Integer</h3><p>法线贴图的类型。</p><p>选项为THREE.TangentSpaceNormalMap（默认）和THREE.ObjectSpaceNormalMap。</p><h3 id="normalscale-vector2" tabindex="-1"><a class="header-anchor" href="#normalscale-vector2" aria-hidden="true">#</a> .normalScale : Vector2</h3><p>法线贴图对材质的影响程度。典型范围是0-1。默认值是Vector2设置为（1,1）。</p><h3 id="reflectivity-float" tabindex="-1"><a class="header-anchor" href="#reflectivity-float" aria-hidden="true">#</a> .reflectivity : Float</h3><p>环境贴图对表面的影响程度; 见.combine。默认值为1，有效范围介于0（无反射）和1（完全反射）之间。</p><h3 id="refractionratio-float" tabindex="-1"><a class="header-anchor" href="#refractionratio-float" aria-hidden="true">#</a> .refractionRatio : Float</h3><p>空气的折射率（IOR）（约为1）除以材质的折射率。它与环境映射模式THREE.CubeRefractionMapping 和THREE.EquirectangularRefractionMapping一起使用。 The index of refraction (IOR) of air (approximately 1) divided by the index of refraction of the material. It is used with environment mapping mode THREE.CubeRefractionMapping. 折射率不应超过1。默认值为0.98。</p><h3 id="specularmap-texture" tabindex="-1"><a class="header-anchor" href="#specularmap-texture" aria-hidden="true">#</a> .specularMap : Texture</h3><p>材质使用的高光贴图。默认值为null。</p><h3 id="wireframe-boolean" tabindex="-1"><a class="header-anchor" href="#wireframe-boolean" aria-hidden="true">#</a> .wireframe : Boolean</h3><p>将几何体渲染为线框。默认值为false（即渲染为平面多边形）。</p><h3 id="wireframelinecap-string" tabindex="-1"><a class="header-anchor" href="#wireframelinecap-string" aria-hidden="true">#</a> .wireframeLinecap : String</h3><p>定义线两端的外观。可选值为 &#39;butt&#39;，&#39;round&#39; 和 &#39;square&#39;。默认为&#39;round&#39;。</p><p>该属性对应2D Canvas lineJoin属性， 并且会被WebGL渲染器忽略。</p><h3 id="wireframelinejoin-string" tabindex="-1"><a class="header-anchor" href="#wireframelinejoin-string" aria-hidden="true">#</a> .wireframeLinejoin : String</h3><p>定义线连接节点的样式。可选值为 &#39;round&#39;, &#39;bevel&#39; 和 &#39;miter&#39;。默认值为 &#39;round&#39;。</p><p>该属性对应2D Canvas lineJoin属性， 并且会被WebGL渲染器忽略。</p><h3 id="wireframelinewidth-float" tabindex="-1"><a class="header-anchor" href="#wireframelinewidth-float" aria-hidden="true">#</a> .wireframeLinewidth : Float</h3><p>控制线框宽度。默认值为1。</p><p>由于OpenGL Core Profile与 大多数平台上WebGL渲染器的限制，无论如何设置该值，线宽始终为1。</p><h2 id="方法" tabindex="-1"><a class="header-anchor" href="#方法" aria-hidden="true">#</a> 方法</h2>',65);function g(_,M){const d=i("IFrame"),t=i("RouterLink");return l(),p("div",null,[c,m,f,u,r(d,{url:"https://luotainxu-demo.netlify.app/#/threejs/material/meshLambertMaterial"}),x,e("p",null,[a("共有属性请参见其基类"),r(t,{to:"/threejs/%E6%9D%90%E8%B4%A8/%E6%9D%90%E8%B4%A8.html"},{default:n(()=>[a("Material")]),_:1})]),b,e("p",null,[a("共有方法请参见其基类"),r(t,{to:"/threejs/%E6%9D%90%E8%B4%A8/%E6%9D%90%E8%B4%A8.html"},{default:n(()=>[a("Material")]),_:1})])])}const T=o(s,[["render",g],["__file","Lambert网格材质.html.vue"]]);export{T as default};
